questoes.correta:
:root {
  --bg: #f5f5f5;
  --text: #222;
  --primary: #6C63FF;
  --font: 'Segoe UI', sans-serif;
}

[data-theme="dark"] {
  --bg: #0a0a23;
  --text: #eee;
  --primary: #6C63FF;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--bg);
  color: var(--text);
  font-family: var(--font);
  line-height: 1.6;
}
